attachments.value:
{%raw%}

<div style="overflow: auto;">
{%- 
    set query = "jobId = '" + job_id + "'"
-%}

{%
    set ns = namespace(eval_output="No Evaluation Status", agent_output="No Output Yet", last_updated="")
%}

{%- 
    set data = engine.query_stream_data("agent_output_stream", cfxql_query=query, sorting=[{"timestamp": "desc" }]) 
-%}

{%-if len(data) > 0 -%}
    {%- set ns.last_updated = data[0]["timestamp"] -%}
{%- endif -%}

{%-for row in data -%}
    {%-if row.get("evaluation_output_0", "") -%}
        {%- set ns.eval_output = json_loads(row.get("evaluation_output_0").strip("```").lstrip("json").strip(" ")).get("agent_run", "")  -%}
    {%- endif -%}
     {%-if row.get("agent_output_0", "") -%}
        {%- set ns.agent_output = row.get("agent_output_0").strip("```").lstrip("html")  -%}
    {%- endif -%}
{%- endfor -%}

{%- if ns.eval_output == "Success" -%}
    {%- set ns.eval_output = "<font style='color: #22dd22;'>"+ns.eval_output + "</font>"-%}
{%- elif ns.eval_output == "Failure" -%}
    {%- set ns.eval_output = "<font style='color: #ff2511;'>"+ns.eval_output + "</font>"-%}
{%- endif -%}

<h3>{{agent_name}}</h3>
<h3>Last Updated: {{ns.last_updated}}</h3>
<h3>Status: {{ns.eval_output}}</h3>
<h3>Output:</h3>
<hr/>
{{ns.agent_output}}

</div>
{%endraw%}

{{ dashboard["dashboard_sections"].clear() }}

{% if conversationId is not defined or conversationId == "" %}
    <div style="background-color: black; color: red; font-weight: bold; padding: 10px;">
        ⚠️ Conversation ID is missing or empty. Cannot proceed further.
    </div>
    {%- set message = "conversationId is missing or empty" -%}

    {{ dashboard["dashboard_sections"].append({
        "title": "No Output",
        "widgets": [{
            "widget_type": "label",
            "uses_reporting_engine": true,
            "fixed_variables": {},
            "height": 1,
            "max_width": 12,
            "label": message,
            "widget_id": "header1",
            "style": {"background-color": "black", "color": "red", "font-weight": "bold", "padding": "10px"}
        }]
    }) }}
{% else %}
    {%- set message = "" -%}

    {%- set cfxql_query = "conversationId = '"+str(conversationId)+"' and final_response = 'true' GET conversationLabel" -%}

    {%- set rows = engine.query_stream_data(
        "rda_chat_sessions",
        cfxql_query=cfxql_query,
        limit=100,
        max_rows=100,
        sorting=[{"timestamp": "asc"}]
    ) -%}

    {%- if not rows -%}
        {%- set message = "This Conversation does not yet have any outputs" -%}
        {{ dashboard["dashboard_sections"].append({
            "title": "No Output",
            "widgets": [{
                "widget_type": "label",
                "uses_reporting_engine": true,
                "fixed_variables": {
                    "conversationId": conversationId,
                    "conversation_id": conversationId
                },
                "height": 1,
                "max_width": 12,
                "label": message,
                "widget_id": "header1",
                "style": {"background-color": "black", "color": "red", "font-weight": "bold", "padding": "10px"}
            }]
        }) }}
    {%- else -%}
        {%- for r in rows -%}
            {{ dashboard["dashboard_sections"].append({
                "title": r.get("conversationLabel", "?"),
                "widgets": [{
                    "widget_type": "label",
                    "uses_reporting_engine": true,
                    "fixed_variables": {
                        "conversationId": conversationId,
                        "conversation_id": conversationId,
                        "conversationLabel": r["conversationLabel"]
                    },
                    "label": "attachment://showOutput",
                    "height": 12,
                    "max_width": 12,
                    "widget_id": "label"+str(len(dashboard["dashboard_sections"]))
                }]
            }) }}
        {%- endfor -%}
    {%- endif -%}
{% endif %}

{%- if conversationId is not defined or conversationLabel is not defined -%}
  <div style="color:red; font-weight:bold;">
    ⚠️ conversationId or conversationLabel not found in context
  </div>
{%- else -%}

  {# ---- Query messages ---- #}
  {%- set cfxql_query = "conversationId = '" ~ (conversationId|default('')) ~ "' and final_response = 'true' and conversationLabel = '" ~ (conversationLabel|default('')) ~ "' GET message" -%}
  {%- set rows = engine.query_stream_data("rda_chat_sessions", cfxql_query=cfxql_query, limit=2, max_rows=2, sorting=[{"timestamp": "asc"}]) | default([], true) -%}

  {%- if rows|length == 0 -%}
    <div style="color:gray;">
      ℹ️ This Conversation does not yet have any outputs.
    </div>
  {%- else -%}
    {%- set raw_message = rows[0].get("message") | default("", true) | string -%}
    {%- set message_out = raw_message -%}

    {# ---- Handle JSON safely ---- #}
    {%- if raw_message is string and raw_message.strip()|length > 0 and raw_message.strip().startswith("json") -%}
      {%- set stripped = (raw_message[4:] | default("", true) | string).strip() -%}
      {%- if stripped|length > 0 -%}
        {%- set parsed = "" -%}
        {%- if stripped is string and stripped|length > 0 -%}
          {%- set parsed = json_loads(stripped) | default("", true) -%}
        {%- endif -%}
        {%- if parsed -%}
          {%- set message_out = json_dumps_indent(parsed, indent=2) | default("⚠️ JSON dump failed", true) -%}
        {%- else -%}
          {%- set message_out = "⚠️ Failed to parse JSON content." -%}
        {%- endif -%}
      {%- else -%}
        {%- set message_out = "⚠️ Empty JSON content." -%}
      {%- endif -%}
    {%- endif -%}

    {# ---- Render Output ---- #}
    <div style="width:100%; height:100%; overflow:auto;">
      {%- if message_out is string and not message_out.strip().startswith("<") -%}
        <div style="white-space: pre-wrap;">{{ message_out }}</div>
      {%- else -%}
        {{ message_out }}
      {%- endif -%}
    </div>
  {%- endif -%}
{%- endif -%}
